  <HEADER encrypted="1" encrypted_ver="1" build="0.0704.1001.0000.13.0" user="z" computer="DESKTOP-LC5V468" date="2025.03.28 07'36'42" map_xs="90" map_ys="90" north_angle="0" extra_map_edge="1" tileset="arctic" environment="Arctic_Final" players="4" name="Остроконечные хребты" id="Rough Ridges" style="0" description="После разгрома ложных богов в районе Теомки, именно сюда падшими квотлами был перенесен странный артефакт, обнаруженный неподалеку от храма Шок. О его силе доподлинно неизвестно, но о ней можно судить хотя бы потому, что артефакт оказался спрятан в одной из самых холодных точек материка: даже карликовые деревья здесь встречаются крайне редко. &#xA; {— От Матвея Icpompeo Аль-Бороди.}" enable_dominance="1" preview_image_ext="tga" version="12" allowable_game_styles="4294967295" default_game_style="-1" victory="255" elimination="1" allies="1" living_world_bird="18" force_rush_rules_disable="0" does_override_teamstyle="0" teamstyle_override_value="0" starts_required="0" starts_no_pick="0" show_all_villages="1" generate_script="0" num_villages="0" num_special="0" num_villages_override="8" num_special_override="9">
